"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[94900],{77583:(e,i,a)=>{a.r(i),a.d(i,{data:()=>n});const n={key:"v-182e7dee",path:"/leaflet/guide/%E7%A4%BA%E4%BE%8B%E4%BB%A3%E7%A0%81/Leaflet%E5%9C%A8%E5%88%87%E7%89%87%E6%95%B0%E6%8D%AE%E6%BA%90%E5%B1%82%E7%BA%A7%E6%9C%89%E9%99%90%E7%9A%84%E6%83%85%E5%86%B5%E4%B8%8B%E6%97%A0%E9%99%90%E5%88%B6%E6%94%BE%E5%A4%A7%E5%9C%B0%E5%9B%BE.html",title:"Leaflet在切片数据源层级有限的情况下无限制放大地图",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"源码地址",slug:"源码地址",children:[]}],git:{updatedTime:1653445943e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"leaflet/guide/示例代码/Leaflet在切片数据源层级有限的情况下无限制放大地图.md"}},68240:(e,i,a)=>{a.r(i),a.d(i,{default:()=>d});const n=(0,a(57293).uE)('<p>[TOC]</p><h1 id="leaflet在切片数据源层级有限的情况下无限制放大地图" tabindex="-1"><a class="header-anchor" href="#leaflet在切片数据源层级有限的情况下无限制放大地图" aria-hidden="true">#</a> Leaflet在切片数据源层级有限的情况下无限制放大地图</h1><p>地图切片服务往往是有限的一般都只有17-20级，可是这种级别往往无法满足业务需求,可是继续放大底图消失也是不行的。</p><p>关键在于<code>L.TileLayer</code>继承自<code>L.GridLayer</code>的<code>maxNativeZoom</code>参数，它可以限制瓦片源最大级别,当地图缩放级别大于这个级别时,会从这个级别请求瓦片然后缩放。</p><p>注意:需要说明一下的是<code>maxNativeZoom</code>必须配合<code>maxZoom</code>使用，否则无效</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>        //初始化地图\n        var map = L.map(&#39;viewDiv&#39;, {\n            crs: L.CRS.EPSG4326,\n            maxZoom: 22,  //矢量数据过于密集,需要放大才能更清晰的看到标注\n            minZoom: 14   //防止过量请求矢量数据,导致地图服务卡死\n\n        }).setView([28.77731514847374, 120.111453538227806], 17);\n        \n        \n                //天地图影像底图\n        var img = L.tileLayer(&#39;http://t4.tianditu.gov.cn/img_c/wmts?tk=fca960333584ee45d72473c3cdb76a20&amp;layer=img&amp;style=default&amp;tilematrixset=c&amp;Service=WMTS&amp;Request=GetTile&amp;Version=1.0.0&amp;Format=tiles&amp;TileMatrix={z}&amp;TileCol={x}&amp;TileRow={y}&#39;, {\n            name: &quot;中国天地图影像&quot;,\n            maxZoom: 22, //设置瓦片最大级别\n            maxNativeZoom: 17,  //瓦片源最大级别,当地图缩放级别大于这个级别时,会从这个级别请求瓦片然后缩放\n            tileSize: 256,  //瓦片大小\n            zoomOffset: 1,  //天地图要设置为1,表示实际瓦片级别比当前地图级别大1\n\n        });\n\n        img.addTo(map);\n        var cia = L.tileLayer(&#39;http://t6.tianditu.gov.cn/cia_c/wmts?tk=fca960333584ee45d72473c3cdb76a20&amp;layer=cia&amp;style=default&amp;tilematrixset=c&amp;Service=WMTS&amp;Request=GetTile&amp;Version=1.0.0&amp;Format=tiles&amp;TileMatrix={z}&amp;TileCol={x}&amp;TileRow={y}&#39;, {\n            name: &quot;中国天地图影像标注&quot;,\n            maxZoom: 22,    //设置瓦片最大级别\n            maxNativeZoom: 17,   //瓦片源最大级别,当地图缩放级别大于这个级别时,会从这个级别请求瓦片然后缩放\n            tileSize: 256,   //瓦片大小\n            zoomOffset: 1    //天地图要设置为1,表示实际瓦片级别比当前地图级别大1\n        }).addTo(map);\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="源码地址" tabindex="-1"><a class="header-anchor" href="#源码地址" aria-hidden="true">#</a> 源码地址</h2><p>链接：https://pan.baidu.com/s/13Ri3JIq4YfPEZNsTtT05TQ 提取码：1ynr</p>',8),l={},d=(0,a(63243).Z)(l,[["render",function(e,i){return n}]])},63243:(e,i)=>{i.Z=(e,i)=>{const a=e.__vccOpts||e;for(const[e,n]of i)a[e]=n;return a}}}]);